from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel with optimized memory access and parallel reduction
fused_operation_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

__global__ void fused_matmul_div_sum_scale_kernel(
    const float* __restrict__ input, 
    const float* __restrict__ weight, 
    float* __restrict__ output, 
    float scaling_factor,
    int batch_size, 
    int input_size, 
    int hidden_size) {

    // Each thread block handles one batch element
    int batch_idx = blockIdx.x;

    if (batch_idx < batch_size) {
        // Shared memory for input row
        extern __shared__ float input_shared[];

        // Coalesced load of input row into shared memory
        for (int i = threadIdx.x; i < input_size; i += blockDim.x) {
            input_shared[i] = input[batch_idx * input_size + i];
        }
        __syncthreads();

        // Thread-local accumulator
        float thread_sum = 0.0f;

        // Process weight rows in parallel across threads
        for (int hidden_idx = threadIdx.x; hidden_idx < hidden_size; hidden_idx += blockDim.x) {
            const float* weight_row = &weight[hidden_idx * input_size];
            float dot_product = 0.0f;

            // Unrolled loop for better performance
            int i = 0;
            for (; i + 3 < input_size; i += 4) {
                dot_product += input_shared[i] * weight_row[i] +
                               input_shared[i+1] * weight_row[i+1] +
                               input_shared[i+2] * weight_row[i+2] +
                               input_shared[i+3] * weight_row[i+3];
            }
            for (; i < input_size; i++) {
                dot_product += input_shared[i] * weight_row[i];
            }

            // Apply division by 2 and accumulate
            thread_sum += dot_product * 0.5f;
        }

        // Parallel reduction within block using shared memory
        __shared__ float shared_sums[256];
        shared_sums[threadIdx.x] = thread_sum;
        __syncthreads();

        // Tree reduction
        for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
            if (threadIdx.x < stride) {
                shared_sums[threadIdx.x] += shared_sums[threadIdx.x + stride];
            }
            __syncthreads();
        }

        // Final scaling and store result
        if (threadIdx.x == 0) {
            output[batch_idx] = shared_sums[0] * scaling_factor;
        }
    }
}

torch::Tensor fused_operation_cuda(
    torch::Tensor input, 
    torch::Tensor weight, 
    float scaling_factor) {

    auto batch_size = input.size(0);
    auto input_size = input.size(1);
    auto hidden_size = weight.size(0);

    // Create output tensor (batch_size, 1)
    auto output = torch::zeros({batch_size, 1}, 
        torch::TensorOptions().dtype(input.dtype()).device(input.device()));

    // Configure kernel launch - optimize block size
    dim3 blocks(batch_size);
    int threads = 256;
    while (threads > hidden_size && threads > 32) {
        threads >>= 1;
    }
    threads = max(32, min(256, threads));

    dim3 grid(blocks);
    size_t shared_mem = input_size * sizeof(float) + threads * sizeof(float);

    fused_matmul_div_sum_scale_kernel<<<grid, threads, shared_mem>>>(
        input.data_ptr<float>(),
        weight.data_ptr<float>(),
        output.data_ptr<float>(),
        scaling_factor,
        batch_size,
        input_size,
        hidden_size
    );

    return output;
}
"""

